(()=>{let t=self;t.addEventListener("push",i=>{if(i.data)try{let n=i.data.json();i.waitUntil(t.registration.showNotification(n.title||"New Notification",{body:n.body,icon:"/icon-192x192.png",badge:"/icon-192x192.png",data:{url:n.url||"/"}}))}catch(t){console.error("Error parsing push notification:",t)}}),t.addEventListener("notificationclick",i=>{i.notification.close(),i.notification.data&&i.notification.data.url&&i.waitUntil(t.clients.matchAll({type:"window",includeUncontrolled:!0}).then(n=>{if(n.length>0){let t=n[0];for(let i=0;i<n.length;i++)n[i].focused&&(t=n[i]);if("focus"in t)return t.focus().then(()=>t.navigate(i.notification.data.url))}return t.clients.openWindow(i.notification.data.url)}))})})();